USERS_FILE  = os.path.join(SYSTEM_DIR, "users.json")
BANNED_FILE = os.path.join(SYSTEM_DIR, "banned.json")

def load_json_file(path):
    if os.path.exists(path):
        try:
            with open(path, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            pass
    return {}

def save_json_file(path, data):
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

def register_user(chat_id, first_name, username):
    """تسجيل مستخدم جديد وإشعار الأدمن"""
    users = load_json_file(USERS_FILE)
    uid   = str(chat_id)
    is_new = uid not in users
    users[uid] = {
        "id":         chat_id,
        "name":       first_name or "بدون اسم",
        "username":   f"@{username}" if username else "بدون يوزر",
        "joined":     users[uid].get("joined", datetime.now().strftime("%Y-%m-%d %H:%M")) if not is_new else datetime.now().strftime("%Y-%m-%d %H:%M"),
        "last_seen":  datetime.now().strftime("%Y-%m-%d %H:%M"),
    }
    save_json_file(USERS_FILE, users)
    # إشعار الأدمن بمستخدم جديد
    if is_new and ADMIN_ID:
        try:
            uname = f"@{username}" if username else "بدون يوزر"
            bot.send_message(
                ADMIN_ID,
                f"🆕 مستخدم جديد!\n"
                f"👤 الاسم: {first_name}\n"
                f"🔗 اليوزر: {uname}\n"
                f"🆔 الـ ID: <code>{chat_id}</code>\n"
                f"🕐 الوقت: {datetime.now().strftime('%Y-%m-%d %H:%M')}",
                parse_mode="HTML"
            )
        except Exception:
            pass

def is_banned(chat_id):
    banned = load_json_file(BANNED_FILE)
    return str(chat_id) in banned

def ban_user(chat_id):
    banned = load_json_file(BANNED_FILE)
    users  = load_json_file(USERS_FILE)
    uid    = str(chat_id)
    info   = users.get(uid, {})
    banned[uid] = {
        "id":       chat_id,
        "name":     info.get("name", "؟"),
        "username": info.get("username", "؟"),
        "banned_at": datetime.now().strftime("%Y-%m-%d %H:%M")
    }
    save_json_file(BANNED_FILE, banned)

def unban_user(chat_id):
    banned = load_json_file(BANNED_FILE)
    banned.pop(str(chat_id), None)
    save_json_file(BANNED_FILE, banned)

def is_admin(chat_id):
    return chat_id == ADMIN_ID

