def get_writable_tmp():
    candidates = [
        os.path.join(os.getcwd(), "tmp_files"),
        tempfile.gettempdir(),
        os.path.expanduser("~"),
        os.getcwd(),
    ]
    for path in candidates:
        try:
            os.makedirs(path, exist_ok=True)
            test = os.path.join(path, ".write_test")
            with open(test, "w") as f:
                f.write("x")
            os.remove(test)
            return path
        except Exception:
            continue
    return os.getcwd()

TMP_DIR = get_writable_tmp()
os.makedirs(TMP_DIR, exist_ok=True)

def tmp_path(filename):
    return os.path.join(TMP_DIR, filename)

