import base64
_START_IMG_B64 = ""
_START_IMG_BYTES = base64.b64decode(_START_IMG_B64)

def send_start_photo(chat_id, caption, reply_markup, reply_to_id=None):
    """يرسل صورة البداية من bytes"""
    import io
    buf = io.BytesIO(_START_IMG_BYTES)
    buf.name = "start.jpg"
    kwargs = {
        "chat_id": chat_id,
        "photo": buf,
        "caption": caption,
        "parse_mode": "HTML",
        "reply_markup": reply_markup
    }
    if reply_to_id:
        kwargs["reply_to_message_id"] = reply_to_id
    bot.send_photo(**kwargs)

