def memory_file(chat_id):
    return os.path.join(SYSTEM_DIR, f"cvv{chat_id}.json")

def model_file(chat_id):
    return os.path.join(SYSTEM_DIR, f"stst0{chat_id}.txt")

def memory_read(chat_id):
    path = memory_file(chat_id)
    if os.path.exists(path):
        try:
            with open(path, "r", encoding="utf-8") as f:
                data = json.load(f)
            if isinstance(data, list):
                return data
        except Exception:
            pass
    return []

def memory_write(chat_id, messages):
    with open(memory_file(chat_id), "w", encoding="utf-8") as f:
        json.dump(messages, f, ensure_ascii=False)

def memory_delete(chat_id):
    path = memory_file(chat_id)
    if os.path.exists(path):
        os.remove(path)
        return True
    return False

def memory_exists(chat_id):
    path = memory_file(chat_id)
    return os.path.exists(path) and os.path.getsize(path) > 2

def memory_add(chat_id, role, text):
    messages = memory_read(chat_id)
    messages.append({"role": role, "text": text, "time": int(time.time())})
    if len(messages) > MEMORY_LIMIT:
        messages = messages[-MEMORY_LIMIT:]
    memory_write(chat_id, messages)

def build_context(chat_id, user_text):
    messages = memory_read(chat_id)
    if not messages:
        return user_text
    context = ""
    for msg in messages[-10:]:
        label = "user" if msg.get("role") == "user" else "assistant"
        context += f"{label}: {msg.get('text', '')}\n\n"
    context += f"user: {user_text}"
    return context

def get_model(chat_id):
    path = model_file(chat_id)
    if os.path.exists(path):
        with open(path, "r") as f:
            return f.read().strip()
    return "v3"

def set_model(chat_id, model):
    with open(model_file(chat_id), "w") as f:
        f.write(model)

