def search_duckduckgo(query):
    """البحث عبر DuckDuckGo API المجاني"""
    try:
        params = {
            "q": query,
            "format": "json",
            "no_html": "1",
            "skip_disambig": "1",
            "t": "architect2099"
        }
        r = requests.get(DDGO_URL, params=params, timeout=10,
                         headers={"User-Agent": "Mozilla/5.0"})
        if r.status_code == 200:
            d = r.json()
            results = []

            # Abstract (ملخص مباشر)
            if d.get("AbstractText"):
                results.append(f"📌 {d['AbstractText']}")
                if d.get("AbstractSource"):
                    results.append(f"   المصدر: {d['AbstractSource']}")

            # Answer مباشر
            if d.get("Answer"):
                results.append(f"✅ الإجابة: {d['Answer']}")

            # Definition
            if d.get("Definition"):
                results.append(f"📖 التعريف: {d['Definition']}")

            # RelatedTopics
            topics = d.get("RelatedTopics", [])[:3]
            for t in topics:
                if isinstance(t, dict) and t.get("Text"):
                    results.append(f"• {t['Text'][:200]}")

            # Infobox
            infobox = d.get("Infobox", {})
            if infobox and infobox.get("content"):
                for item in infobox["content"][:5]:
                    if item.get("label") and item.get("value"):
                        results.append(f"  {item['label']}: {item['value']}")

            if results:
                return "\n".join(results)
    except Exception as e:
        print(f"[DuckDuckGo] {e}")
    return None

def search_wikipedia(query, lang="ar"):
    """البحث في ويكيبيديا"""
    try:
        base = WIKI_AR_URL if lang == "ar" else WIKI_EN_URL
        # تنظيف الاستعلام
        clean_q = query.strip().replace(" ", "_")
        r = requests.get(
            f"{base}{requests.utils.quote(clean_q)}",
            timeout=10,
            headers={"User-Agent": "ArchitectBot/2.0"}
        )
        if r.status_code == 200:
            d = r.json()
            if d.get("extract") and len(d["extract"]) > 50:
                title   = d.get("title", "")
                extract = d["extract"][:600]
                result  = f"📚 {title}\n{extract}"
                if d.get("content_urls", {}).get("desktop", {}).get("page"):
                    result += f"\n🔗 {d['content_urls']['desktop']['page']}"
                return result
    except Exception as e:
        print(f"[Wikipedia {lang}] {e}")
    return None

def get_weather(city):
    """الطقس عبر wttr.in"""
    try:
        r = requests.get(
            f"{WEATHER_URL}{requests.utils.quote(city)}",
            params={"format": "j1", "lang": "ar"},
            timeout=10
        )
        if r.status_code == 200:
            d = r.json()
            current = d["current_condition"][0]
            area    = d["nearest_area"][0]
            city_name = area["areaName"][0]["value"]
            country   = area["country"][0]["value"]
            temp_c    = current["temp_C"]
            feels     = current["FeelsLikeC"]
            desc      = current["lang_ar"][0]["value"] if current.get("lang_ar") else current["weatherDesc"][0]["value"]
            humidity  = current["humidity"]
            wind      = current["windspeedKmph"]
            uv        = current.get("uvIndex", "?")

            # توقعات 3 أيام
            forecast_lines = []
            for day in d["weather"][:3]:
                date_str = day["date"]
                max_t    = day["maxtempC"]
                min_t    = day["mintempC"]
                forecast_lines.append(f"  {date_str}: 🔺{max_t}° / 🔻{min_t}°")

            return (
                f"🌍 الطقس في {city_name}, {country}\n"
                f"🌡️ الحرارة: {temp_c}°C (يبدو كـ {feels}°C)\n"
                f"☁️ الحالة: {desc}\n"
                f"💧 الرطوبة: {humidity}%\n"
                f"💨 الرياح: {wind} كم/ساعة\n"
                f"☀️ مؤشر UV: {uv}\n\n"
                f"📅 التوقعات:\n" + "\n".join(forecast_lines)
            )
    except Exception as e:
        print(f"[Weather] {e}")
    return None

def get_crypto_price(coin):
    """سعر العملات الرقمية من CoinGecko"""
    try:
        coin_map = {
            "bitcoin": "bitcoin", "btc": "bitcoin",
            "ethereum": "ethereum", "eth": "ethereum",
            "dogecoin": "dogecoin", "doge": "dogecoin",
            "tether": "tether", "usdt": "tether",
            "bnb": "binancecoin", "solana": "solana", "sol": "solana",
            "xrp": "ripple", "cardano": "cardano", "ada": "cardano",
        }
        coin_id = coin_map.get(coin.lower(), coin.lower())
        r = requests.get(
            f"https://api.coingecko.com/api/v3/simple/price",
            params={"ids": coin_id, "vs_currencies": "usd,sar", "include_24hr_change": "true"},
            timeout=10
        )
        if r.status_code == 200:
            d = r.json()
            if coin_id in d:
                data    = d[coin_id]
                usd     = data.get("usd", "?")
                sar     = data.get("sar", "?")
                change  = data.get("usd_24h_change", 0)
                arrow   = "📈" if change >= 0 else "📉"
                return (
                    f"💰 {coin.upper()}\n"
                    f"  💵 USD: ${usd:,.2f}\n"
                    f"  🇸🇦 SAR: {sar:,.2f} ر.س\n"
                    f"  {arrow} 24h: {change:+.2f}%"
                )
    except Exception as e:
        print(f"[Crypto] {e}")
    return None

def get_exchange_rate(from_cur, to_cur, amount=1):
    """أسعار الصرف"""
    try:
        r = requests.get(
            f"https://api.exchangerate-api.com/v4/latest/{from_cur.upper()}",
            timeout=10
        )
        if r.status_code == 200:
            d = r.json()
            rates = d.get("rates", {})
            to_rate = rates.get(to_cur.upper())
            if to_rate:
                result = amount * to_rate
                return (
                    f"💱 سعر الصرف\n"
                    f"  {amount} {from_cur.upper()} = {result:.4f} {to_cur.upper()}\n"
                    f"  📅 آخر تحديث: {d.get('date', '?')}"
                )
    except Exception as e:
        print(f"[Exchange] {e}")
    return None

def smart_web_search(query):
    """
    بحث ذكي — يختار المصدر الأنسب حسب نوع الاستعلام
    ويجمع من أكثر من مصدر لو ممكن
    """
    query_lower = query.lower()
    results = []

    # ── طقس ──────────────────────────────────────────────────────
    weather_kw = ["طقس", "weather", "حرارة", "temperature", "مناخ", "climate", "درجة الحرارة"]
    if any(k in query_lower for k in weather_kw):
        city = re.sub(r'طقس|weather|حرارة|temperature|في|in|بـ|بالـ', '', query, flags=re.IGNORECASE).strip()
        if not city:
            city = "Cairo"
        res = get_weather(city)
        if res:
            return f"🌤️ معلومات الطقس:\n{res}"

    # ── عملات رقمية ───────────────────────────────────────────────
    crypto_kw = ["bitcoin", "btc", "ethereum", "eth", "crypto", "عملة رقمية",
                 "دوجكوين", "dogecoin", "solana", "sol", "سعر عملة", "binance", "bnb"]
    if any(k in query_lower for k in crypto_kw):
        for coin in ["bitcoin", "btc", "ethereum", "eth", "dogecoin", "doge",
                     "solana", "sol", "bnb", "xrp", "ada"]:
            if coin in query_lower:
                res = get_crypto_price(coin)
                if res:
                    return f"📊 بيانات العملة:\n{res}"

    # ── أسعار صرف ─────────────────────────────────────────────────
    fx_kw = ["صرف", "exchange", "دولار", "dollar", "يورو", "euro", "جنيه", "ريال", "درهم"]
    if any(k in query_lower for k in fx_kw):
        pairs = [("USD","EGP"), ("USD","SAR"), ("USD","AED"), ("EUR","USD"),
                 ("GBP","USD"), ("USD","IQD"), ("USD","JOD")]
        for (f, t) in pairs:
            if f.lower() in query_lower or t.lower() in query_lower:
                res = get_exchange_rate(f, t)
                if res:
                    results.append(res)
                    break
        if not results:
            res = get_exchange_rate("USD", "EGP")
            if res:
                results.append(res)

    # ── ويكيبيديا (معلومات وتعريفات) ─────────────────────────────
    wiki_kw = ["من هو", "ما هو", "ما هي", "عرف", "اشرح", "تاريخ", "who is",
               "what is", "define", "history", "معلومات عن", "info about"]
    do_wiki = any(k in query_lower for k in wiki_kw) or len(query.split()) <= 5

    if do_wiki:
        # جرب عربي أولاً ثم إنجليزي
        wiki_q = re.sub(r'من هو|ما هو|ما هي|عرف|اشرح|who is|what is|define|معلومات عن|info about',
                        '', query, flags=re.IGNORECASE).strip()
        res = search_wikipedia(wiki_q, lang="ar")
        if not res:
            res = search_wikipedia(wiki_q, lang="en")
        if res:
            results.append(res)

    # ── DuckDuckGo (بحث عام) ──────────────────────────────────────
    ddg = search_duckduckgo(query)
    if ddg:
        results.append(f"🔍 نتائج البحث:\n{ddg}")

    if results:
        return "\n\n".join(results)

    return None

