LANG_EXT = {
    "python":"py","javascript":"js","js":"js","html":"html","css":"css",
    "php":"php","java":"java","c":"c","cpp":"cpp","c++":"cpp","cs":"cs",
    "c#":"cs","ruby":"rb","go":"go","rust":"rs","swift":"swift","kotlin":"kt",
    "bash":"sh","shell":"sh","sql":"sql","json":"json","xml":"xml",
    "markdown":"md","md":"md","txt":"txt","typescript":"ts","ts":"ts"
}

def extract_code_blocks(text):
    result = []
    for m in re.finditer(r'```(\w+)?\s*\n([\s\S]*?)```', text):
        result.append({
            "lang":       m.group(1) or "txt",
            "code":       m.group(2).strip(),
            "full_match": m.group(0)
        })
    return result

def vip_code2(text):
    blocks = extract_code_blocks(text)
    if not blocks:
        return None
    rand_num = random.randint(10, 99)

    if len(blocks) == 1:
        block = blocks[0]
        ext   = LANG_EXT.get(block["lang"].lower(), "txt")
        filename     = f"code_{rand_num}.{ext}"
        file_content = f"```{block['lang']}\n{block['code']}\n```\n"
        modified_text = text.replace(block["full_match"], f"`{filename}`")
    else:
        filename      = f"code_{rand_num}.txt"
        file_content  = ""
        modified_text = text
        for i, block in enumerate(blocks):
            file_content  += f"Code {i+1}\n#==========================\n"
            file_content  += f"```{block['lang']}\n{block['code']}\n```\n"
            file_content  += "#==========================\n\n"
            modified_text  = modified_text.replace(block["full_match"], f"`Code :{i+1}`")
        modified_text = modified_text.strip()
        note = f"• **The codes were moved to the file** (`{filename}`)"
        modified_text = (modified_text + f"\n\n{note}") if modified_text else note

    filepath = tmp_path(filename)
    with open(filepath, "w", encoding="utf-8") as f:
        f.write(file_content)

    return {"path": filepath, "filename": filename, "count": len(blocks), "text": modified_text}

def vip_code3(text):
    bt = text.count("`")
    tr = text.count("```")
    if bt > 0 and tr == 0:
        if bt % 2 == 0:
            return True
        lines, fixed = text.split("\n"), []
        for line in lines:
            if line.count("`") == 1:
                pos = line.index("`")
                if pos < 5:             line += "`"
                elif pos > len(line)-5: line = "`" + line
            fixed.append(line)
        return "\n".join(fixed).count("`") % 2 == 0
    if tr > 0:
        if tr % 2 != 0:
            return False
        inside = False
        for line in text.split("\n"):
            if line.strip().startswith("```"):
                inside = not inside
        return not inside
    if abs(text.count("[") - text.count("]")) > 2: return False
    if abs(text.count("(") - text.count(")")) > 2: return False
    if text.count("*") % 2 != 0 and text.count("*") > 3: return False
    if text.count("_") % 2 != 0 and text.count("_") > 3: return False
    return True

def vip_code4(text):
    if not text:
        return text
    text = re.sub(r'(#+)([^#\s])', r'\1 \2', text)
    text = re.sub(r'(#+)\s+',      r'\1 ',   text)
    bt = text.count("`")
    tr = text.count("```")
    if bt > 0 and tr == 0 and bt % 2 != 0:
        text += "`"
    for ch in "\x00\x01\x02\x03\x04\x05\x06\x07\x08\x0B\x0C\x0E\x0F":
        text = text.replace(ch, "")
    text = re.sub(r'[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]', '', text)
    text = text.encode("utf-8", errors="ignore").decode("utf-8", errors="ignore")
    return text

