def vip_request(url, data=None, params=None):
    headers = {"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64)"}
    try:
        if data is not None:
            r = requests.post(url, data=data, headers=headers, timeout=25, verify=False)
        else:
            r = requests.get(url, params=params, headers=headers, timeout=25, verify=False)
        if r.status_code == 200:
            return r.text
        if data is None and params:
            r2 = requests.post(url, data=params, headers=headers, timeout=25, verify=False)
            if r2.status_code == 200:
                return r2.text
    except Exception as e:
        print(f"[vip_request] {e}")
    return None

def parse_sii3_response(r):
    if not r or len(r.strip()) < 3:
        return None
    text = r.strip()
    try:
        d = json.loads(text)
        result = (d.get("response") or d.get("result") or d.get("text") or
                  d.get("reply") or d.get("answer") or d.get("message") or
                  d.get("output") or d.get("data"))
        if result and len(str(result).strip()) > 3:
            return str(result).strip()
        if len(text) > 10:
            return text
    except Exception:
        pass
    if len(text) > 3:
        return text
    return None

# ── 1. DeepSeek (الأساسي) ────────────────────────────────────────
def try_deepseek_main(chat_id, prompt):
    model = get_model(chat_id)
    rs = vip_request(DARK_URL, data={"key": DARK_KEY, model: prompt})
    if rs:
        try:
            d = json.loads(rs)
            if d.get("status") == "success":
                resp = d.get("response", "")
                if resp and len(resp.strip()) > 3:
                    return resp.strip()
            resp = d.get("response") or d.get("result") or d.get("text")
            if resp and len(str(resp).strip()) > 3:
                return str(resp).strip()
        except Exception:
            if len(rs.strip()) > 10:
                return rs.strip()
    return None

