    for m in history[-10:]:
        messages.append({
            "role": m["role"] if m["role"] in ("user","assistant") else "user",
            "content": m["text"]
        })
    content = prompt
    if file_text:
        content = f"محتوى الملف:\n```\n{file_text[:3000]}\n```\n\nالطلب: {prompt}"
