# ── المحرك الرئيسي + ويب سيرش ────────────────────────────────────
def global_ai(chat_id, prompt, file_text=None, force_search=False):
    """
    سلسلة Fallback كاملة مع دعم البحث في الويب:
    1. DeepSeek V3/R1 (DARK API)
    2. Gemini Pro  → OpenAI → DeepSeek → Shereen  (sii3)
    3. Groq llama3-3-70b
    4. OpenRouter GPT-3.5 (k1/k2) + Mistral + Llama (free)
    5. OpenRouter Claude-3-haiku
    """
    context = build_context(chat_id, prompt)

    # ── بحث في الويب ─────────────────────────────────────────────
    web_info = ""
    if force_search or needs_web_search(prompt):
        print(f"[WebSearch] ابحث عن: {prompt[:60]}")
        web_result = smart_web_search(prompt)
        if web_result:
            web_info = web_result
            print(f"[WebSearch] ✅ نتيجة ({len(web_info)} حرف)")

    # ── تجميع الـ prompt مع معلومات الويب ────────────────────────
    enriched_prompt = prompt
    if web_info:
        enriched_prompt = (
            f"معلومات من الإنترنت (استخدمها في إجابتك):\n"
            f"{'='*40}\n{web_info}\n{'='*40}\n\n"
            f"سؤال المستخدم: {prompt}"
        )

    # DeepSeek مع السياق
    enriched_context = build_context(chat_id, enriched_prompt)

    steps = [
        ("DeepSeek-DARK",   lambda: try_deepseek_main(chat_id, enriched_context)),
        ("Gemini-sii3",     lambda: try_gemini(enriched_prompt)),
        ("OpenAI-sii3",     lambda: try_openai_sii3(enriched_prompt)),
        ("DeepSeek-sii3",   lambda: try_deepseek_sii3(enriched_prompt)),
        ("Shereen-sii3",    lambda: try_shereen(enriched_prompt)),
        ("Groq",            lambda: try_groq(chat_id, enriched_prompt,
                                             extra_context=web_info, file_text=file_text)),
        ("OR-GPT35-k1",     lambda: try_openrouter(chat_id, enriched_prompt, OPENROUTER_KEY_1,
                                                    extra_context=web_info, file_text=file_text)),
        ("OR-GPT35-k2",     lambda: try_openrouter(chat_id, enriched_prompt, OPENROUTER_KEY_2,
                                                    extra_context=web_info, file_text=file_text)),
        ("OR-Mistral-free", lambda: try_openrouter(chat_id, enriched_prompt, OPENROUTER_KEY_1,
                                                    model="mistralai/mistral-7b-instruct:free",
                                                    extra_context=web_info, file_text=file_text)),
        ("OR-Llama-free",   lambda: try_openrouter(chat_id, enriched_prompt, OPENROUTER_KEY_1,
                                                    model="meta-llama/llama-3.1-8b-instruct:free",
                                                    extra_context=web_info, file_text=file_text)),
        ("OR-Claude",       lambda: try_openrouter(chat_id, enriched_prompt, OPENROUTER_KEY_1,
                                                    model="anthropic/claude-3-haiku",
                                                    extra_context=web_info, file_text=file_text)),
    ]

    for name, fn in steps:
        try:
            result = fn()
            if result and len(str(result).strip()) > 5:
                print(f"[AI] ✅ {name}")
                memory_add(chat_id, "user", prompt)
                memory_add(chat_id, "assistant", str(result))
                return str(result)
            else:
                print(f"[AI] ⏭ {name} فارغ")
        except Exception as e:
            print(f"[AI] ❌ {name}: {e}")

    # لو كان في نتيجة بحث بس AI فشل — رجع نتيجة البحث مباشرة
    if web_info:
        memory_add(chat_id, "user", prompt)
        memory_add(chat_id, "assistant", web_info)
        return f"📡 نتائج البحث:\n\n{web_info}"

    return "⚠️ جميع المحركات غير متاحة حالياً. حاول مرة أخرى."

