def generate_image(chat_id, prompt):
    try:
        r = requests.get(API_IMAGE_GEN, params={"text": prompt}, timeout=30)
        if r.status_code == 200:
            ct = r.headers.get("content-type", "")
            if ct.startswith("image"):
                fp = tmp_path(f"gen_{chat_id}.jpg")
                with open(fp, "wb") as f:
                    f.write(r.content)
                with open(fp, "rb") as f:
                    bot.send_photo(chat_id, f, caption=f"🎨 {prompt[:100]}\n\n© {OWNER_NAME} | {OWNER_USER}")
                os.remove(fp)
                return True
            try:
                d = r.json()
                img_url = d.get("url") or d.get("image") or d.get("result")
                if img_url:
                    bot.send_photo(chat_id, img_url, caption=f"🎨 {prompt[:100]}\n\n© {OWNER_NAME} | {OWNER_USER}")
                    return True
            except Exception:
                pass
    except Exception as e:
        print(f"[Image Gen] {e}")
    return False

