@bot.callback_query_handler(func=lambda call: True)
def handle_callback(call: CallbackQuery):
    chat_id = call.message.chat.id
    mid     = call.message.message_id
    data    = call.data

    if data == "model10":
        current   = get_model(chat_id)
        new_model = "r1" if current == "v3" else "v3"
        set_model(chat_id, new_model)
        mode_name = "Thinker R1 🧠" if new_model == "r1" else "V3 عادي"
        bot.answer_callback_query(call.id,
            text=f"✅ تم التحويل إلى {mode_name}", show_alert=False)
        bot.edit_message_reply_markup(chat_id=chat_id, message_id=mid,
            reply_markup=system_keyboard(chat_id))

    elif data == "deletemem":
        if memory_delete(chat_id):
            bot.answer_callback_query(call.id, text="🗑 تم حذف الذاكرة بنجاح", show_alert=False)
            bot.edit_message_reply_markup(chat_id=chat_id, message_id=mid,
                reply_markup=system_keyboard(chat_id))
        else:
            bot.answer_callback_query(call.id, text="لا يوجد شيء للحذف", show_alert=False)

    elif data == "system":
        bot.edit_message_reply_markup(chat_id=chat_id, message_id=mid,
            reply_markup=system_keyboard(chat_id))

    elif data == "back":
        bot.edit_message_reply_markup(chat_id=chat_id, message_id=mid,
            reply_markup=main_keyboard())

    elif data == "stats":
        mem = memory_read(chat_id)
        model = get_model(chat_id)
        text = (
            f"📊 إحصائياتك:\n"
            f"• الرسائل المحفوظة: {len(mem)}/{MEMORY_LIMIT}\n"
            f"• الموديل الحالي: {'Thinker R1 🧠' if model == 'r1' else 'DeepSeek V3'}\n"
            f"• الذاكرة: {'✅ نشطة' if mem else '❌ فارغة'}\n"
            f"• {BOT_NAME} {VERSION}\n"
            f"• © {OWNER_NAME} | {OWNER_USER}"
        )
        bot.answer_callback_query(call.id, text=text, show_alert=True)

    elif data == "clear_mem":
        if memory_delete(chat_id):
            bot.answer_callback_query(call.id, text="✅ تم مسح الذاكرة بنجاح!", show_alert=False)
            try:
                bot.edit_message_reply_markup(chat_id=chat_id, message_id=mid,
                    reply_markup=reply_keyboard())
            except Exception:
                pass
        else:
            bot.answer_callback_query(call.id, text="الذاكرة فارغة أصلاً", show_alert=False)

    elif data == "new_q":
        bot.answer_callback_query(call.id, text="✍️ اكتب سؤالك الجديد", show_alert=False)
        bot.send_message(chat_id, "✍️ اكتب سؤالك أو طلبك الجديد:")

    elif data == "show_mem":
        mem = memory_read(chat_id)
        if not mem:
            bot.answer_callback_query(call.id, text="الذاكرة فارغة حالياً", show_alert=True)
            return
        lines = [f"💾 الذاكرة ({len(mem)} رسالة)\n━━━━━━━━━━━━━━━━━━━━"]
        for m in mem[-10:]:
            role  = "👤" if m.get("role") == "user" else "🤖"
            txt   = m.get("text","")[:80]
            lines.append(f"{role} {txt}{'...' if len(m.get('text','')) > 80 else ''}")
        summary = "\n".join(lines)
        if len(summary) > 200:
            summary = summary[:197] + "..."
        bot.answer_callback_query(call.id, text=summary, show_alert=True)


        text = (
            "🔍 البحث في الويب:\n\n"
            "البوت يبحث تلقائياً عند سؤالك عن:\n"
            "• الطقس: 'طقس القاهرة'\n"
            "• العملات: 'سعر البيتكوين'\n"
            "• الصرف: 'سعر الدولار'\n"
            "• معلومات: 'من هو نيوتن'\n"
            "• ويكيبيديا: 'ما هو الذكاء الاصطناعي'\n\n"
            "أو استخدم /search للبحث المباشر"
        )
        bot.answer_callback_query(call.id, text=text, show_alert=True)

