@bot.message_handler(content_types=["document"])
def handle_document(message: Message):
    chat_id  = message.chat.id
    doc      = message.document
    caption  = message.caption or "حلل هذا الملف واشرحه بالتفصيل"
    filename = doc.file_name or "file"
    _, ext   = os.path.splitext(filename.lower())

    text_exts = {
        ".py",".js",".ts",".html",".css",".txt",".json",".xml",
        ".md",".csv",".php",".c",".cpp",".java",".go",".rs",
        ".sh",".bat",".yaml",".yml",".ini",".env",".sql",".rb"
    }

    bot.send_chat_action(chat_id, "typing")

    if ext in text_exts or (doc.mime_type and "text" in doc.mime_type):
        try:
            fi      = bot.get_file(doc.file_id)
            url     = f"https://api.telegram.org/file/bot{TOKEN}/{fi.file_path}"
            content = requests.get(url, timeout=15).text[:4000]
            prompt  = f'This is inside the file ({filename})\n"""\n{content}\n"""\n'
            if caption != "حلل هذا الملف واشرحه بالتفصيل":
                prompt += caption
            bot.send_message(chat_id, f"📂 جاري تحليل: {filename} ...")
            res = global_ai(chat_id, prompt, file_text=content)
            send_response(chat_id, res, reply_to_id=message.message_id)
        except Exception as e:
            bot.reply_to(message, f"⚠️ تعذر قراءة الملف: {e}")
    else:
        res = global_ai(chat_id, f"المستخدم أرسل ملفاً باسم '{filename}'. {caption}")
        send_response(chat_id, res, reply_to_id=message.message_id)

