@bot.message_handler(func=lambda m: True, content_types=["text"])
def handle_text(message: Message):
    chat_id   = message.chat.id
    user_text = message.text.strip()
    if not user_text:
        return

    # ── تسجيل المستخدم ────────────────────────────────────────────
    register_user(chat_id, message.from_user.first_name, message.from_user.username or "")

    # ── فحص الحظر ────────────────────────────────────────────────
    if is_banned(chat_id):
        bot.reply_to(message, "🚫 أنت محظور من استخدام البوت.")
        return

    # ── معالجة حالات الأدمن (broadcast / dm / ban / unban) ────────
    if is_admin(chat_id) and chat_id in admin_state:
        state = admin_state.pop(chat_id)

        if state == "broadcast":
            _do_broadcast(chat_id, user_text)
            return

        elif state == "dm_wait_id":
            parts = user_text.split("\n", 1)
            if len(parts) < 2:
                bot.reply_to(message, "⚠️ اكتب الـ ID في السطر الأول والرسالة في السطر التاني.")
                return
            try:
                uid  = int(parts[0].strip())
                text = parts[1].strip()
                bot.send_message(uid, f"📩 رسالة من الإدارة:\n\n{text}")
                bot.reply_to(message, f"✅ تم الإرسال للـ ID: <code>{uid}</code>", parse_mode="HTML")
            except Exception as e:
                bot.reply_to(message, f"⚠️ فشل الإرسال: {e}")
            return

        elif state == "ban":
            try:
                uid = int(user_text.strip())
                ban_user(uid)
                bot.reply_to(message, f"🚫 تم حظر: <code>{uid}</code>", parse_mode="HTML")
            except Exception as e:
                bot.reply_to(message, f"⚠️ خطأ: {e}")
            return

        elif state == "unban":
            try:
                uid = int(user_text.strip())
                unban_user(uid)
                bot.reply_to(message, f"✅ تم رفع الحظر عن: <code>{uid}</code>", parse_mode="HTML")
            except Exception as e:
                bot.reply_to(message, f"⚠️ خطأ: {e}")
            return

    bot.send_chat_action(chat_id, "typing")

    # ── فلتر الأمان أولاً ─────────────────────────────────────────
    blocked = security_filter(user_text)
    if blocked:
        send_response(chat_id, blocked, reply_to_id=message.message_id)
        return

    # ── كشف الغموض ────────────────────────────────────────────────
    if is_ambiguous(user_text):
        ask_clarification(chat_id, user_text, reply_to_id=message.message_id)
        return

    # طلب صورة
    img_kw = ["صور","ولد صورة","اعمل صورة","ارسم","generate image","draw"]
    if any(k in user_text.lower() for k in img_kw):
        prompt = user_text
        for k in img_kw:
            prompt = prompt.replace(k, "").strip()
        if prompt:
            bot.send_chat_action(chat_id, "upload_photo")
            bot.send_message(chat_id, "🎨 جاري توليد الصورة...")
            if not generate_image(chat_id, prompt):
                bot.send_message(chat_id, "⚠️ تعذر توليد الصورة، جاري الرد نصياً...")
                res = global_ai(chat_id, user_text)
                send_response(chat_id, res, reply_to_id=message.message_id)
            return

    # طلب كود
    if is_code_request(user_text):
        bot.send_message(chat_id, "🛠️ جاري التوليد...")
        code = generate_code(chat_id, user_text)
        if code and len(code) > 50:
            filename = detect_filename(user_text)
            clean = clean_code(code)
            fp = tmp_path(filename)
            try:
                with open(fp, "w", encoding="utf-8") as f:
                    f.write(clean)
                with open(fp, "rb") as f:
                    bot.send_document(
                        chat_id, f,
                        caption=f"✅ تم التوليد بنجاح\n© {OWNER_NAME} | {OWNER_USER}"
                    )
            except Exception as e:
                bot.send_message(chat_id, f"⚠️ خطأ في حفظ الملف: {e}")
            finally:
                if os.path.exists(fp):
                    os.remove(fp)
            return
        # fallback
        res = global_ai(chat_id, user_text)
        send_response(chat_id, res, reply_to_id=message.message_id)
        return

    # سؤال عادي (مع بحث تلقائي إذا لزم)
    res = global_ai(chat_id, user_text)
    send_response(chat_id, res, reply_to_id=message.message_id)

