# حالة انتظار الأدمن (broadcast / dm / ban / unban)
admin_state = {}

@bot.message_handler(commands=["admin"])
def cmd_admin(message: Message):
    if not is_admin(message.chat.id):
        return
    users  = load_json_file(USERS_FILE)
    banned = load_json_file(BANNED_FILE)
    text = (
        f"🛡️ <b>لوحة التحكم</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n"
        f"👥 المستخدمين: <b>{len(users)}</b>\n"
        f"🚫 المحظورين: <b>{len(banned)}</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n"
        f"اختر من القائمة:"
    )
    bot.send_message(message.chat.id, text, parse_mode="HTML", reply_markup=admin_keyboard())

@bot.message_handler(commands=["broadcast"])
def cmd_broadcast(message: Message):
    if not is_admin(message.chat.id):
        return
    text = message.text.replace("/broadcast", "").strip()
    if not text:
        admin_state[message.chat.id] = "broadcast"
        bot.reply_to(message, "📢 اكتب الرسالة اللي عايز تبعتها لكل المستخدمين:")
        return
    _do_broadcast(message.chat.id, text)

@bot.message_handler(commands=["dm"])
def cmd_dm(message: Message):
    if not is_admin(message.chat.id):
        return
    parts = message.text.replace("/dm", "").strip().split("\n", 1)
    if len(parts) < 2:
        admin_state[message.chat.id] = "dm_wait_id"
        bot.reply_to(message, "✉️ اكتب الـ ID ثم الرسالة في سطر جديد:\n\nمثال:\n123456789\nمرحبا يا صاحبي!")
        return
    try:
        uid  = int(parts[0].strip())
        text = parts[1].strip()
        bot.send_message(uid, f"📩 رسالة من الإدارة:\n\n{text}")
        bot.reply_to(message, f"✅ تم الإرسال للـ ID: {uid}")
    except Exception as e:
        bot.reply_to(message, f"⚠️ فشل الإرسال: {e}")

