@bot.message_handler(commands=["users"])
def cmd_users(message: Message):
    if not is_admin(message.chat.id):
        return
    users = load_json_file(USERS_FILE)
    if not users:
        bot.reply_to(message, "لا يوجد مستخدمين بعد.")
        return
    lines = [f"👥 <b>المستخدمين ({len(users)})</b>\n━━━━━━━━━━━━━━━━━━━━"]
    for u in list(users.values())[-20:]:
        lines.append(f"• {u['name']} | {u['username']} | <code>{u['id']}</code>")
    bot.send_message(message.chat.id, "\n".join(lines), parse_mode="HTML")

def _do_broadcast(admin_id, text):
    users   = load_json_file(USERS_FILE)
    banned  = load_json_file(BANNED_FILE)
    success = 0
    failed  = 0
    for uid, info in users.items():
        if uid in banned:
            continue
        try:
            bot.send_message(int(uid), f"📢 رسالة من الإدارة:\n\n{text}")
            success += 1
        except Exception:
            failed += 1
    bot.send_message(admin_id, f"📢 تم الإرسال!\n✅ نجح: {success}\n❌ فشل: {failed}")

# ── Callback الأدمن ───────────────────────────────────────────────
@bot.callback_query_handler(func=lambda c: c.data.startswith("adm_"))
def handle_admin_callback(call: CallbackQuery):
    chat_id = call.message.chat.id
    if not is_admin(chat_id):
        bot.answer_callback_query(call.id, "⛔ غير مصرح", show_alert=True)
        return

    data = call.data

    if data == "adm_users":
        users = load_json_file(USERS_FILE)
        lines = [f"👥 <b>المستخدمين ({len(users)})</b>\n━━━━━━━━━━━━━━━━━━━━"]
        for u in list(users.values())[-20:]:
            lines.append(f"• {u['name']} | {u['username']} | <code>{u['id']}</code>")
        bot.send_message(chat_id, "\n".join(lines) if len(lines)>1 else "لا يوجد مستخدمين.", parse_mode="HTML")

    elif data == "adm_banned":
        banned = load_json_file(BANNED_FILE)
        if not banned:
            bot.answer_callback_query(call.id, "لا يوجد محظورين.", show_alert=True)
            return
        lines = [f"🚫 <b>المحظورين ({len(banned)})</b>\n━━━━━━━━━━━━━━━━━━━━"]
        for u in banned.values():
            lines.append(f"• {u['name']} | {u['username']} | <code>{u['id']}</code>")
        bot.send_message(chat_id, "\n".join(lines), parse_mode="HTML")

    elif data == "adm_broadcast":
        admin_state[chat_id] = "broadcast"
        bot.send_message(chat_id, "📢 اكتب الرسالة اللي عايز تبعتها لكل المستخدمين:")

    elif data == "adm_dm":
        admin_state[chat_id] = "dm_wait_id"
        bot.send_message(chat_id, "✉️ اكتب الـ ID ثم الرسالة في سطر جديد:\n\nمثال:\n123456789\nمرحبا يا صاحبي!")

    elif data == "adm_ban":
        admin_state[chat_id] = "ban"
        bot.send_message(chat_id, "🔨 اكتب الـ ID اللي عايز تحظره:")

    elif data == "adm_unban":
        admin_state[chat_id] = "unban"
        bot.send_message(chat_id, "✅ اكتب الـ ID اللي عايز ترفع حظره:")

    bot.answer_callback_query(call.id)

